import React, { useEffect, useRef, useState } from 'react';
import './Sidebar.css';

const NAV_ITEMS = [
  {
    key: 'home',
    label: 'Home',
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
        <path d="M3 10.5 12 3l9 7.5" />
        <path d="M5.5 9.5V21h13V9.5" />
      </svg>
    ),
  },
  {
    key: 'projects',
    label: 'Projects',
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
        <rect x="4" y="4" width="6" height="6" />
        <rect x="14" y="4" width="6" height="6" />
        <rect x="4" y="14" width="6" height="6" />
        <rect x="14" y="14" width="6" height="6" />
      </svg>
    ),
  },
  {
    key: 'experience',
    label: 'Experience',
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
        <path d="M4 6h14" />
        <path d="M4 12h10" />
        <path d="M4 18h16" />
        <circle cx="20" cy="6" r="1.6" fill="currentColor" stroke="none" />
      </svg>
    ),
  },
  {
    key: 'contact',
    label: 'Contact',
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
        <rect x="3" y="6" width="18" height="12" rx="2" />
        <path d="m4 8 8 6 8-6" />
      </svg>
    ),
  },
];

function LogoMark() {
  return (
    <div className="logo-mark" aria-hidden="true">
      <span className="logo-ac">AC</span>
      <span className="logo-app app-pr">Pr</span>
      <span className="logo-app app-ae">Ae</span>
      <span className="logo-app app-cc">Cc</span>
    </div>
  );
}

export default function Sidebar({ activePage, onNavigate }) {
  const [mobileOpen, setMobileOpen] = useState(false);
  const [mobileClosing, setMobileClosing] = useState(false);
  const timeoutsRef = useRef([]);
  const rafRef = useRef(null);

  const clearTimers = () => {
    timeoutsRef.current.forEach((timeoutId) => clearTimeout(timeoutId));
    timeoutsRef.current = [];
    if (rafRef.current) {
      cancelAnimationFrame(rafRef.current);
      rafRef.current = null;
    }
  };

  const queueTimeout = (callback, delay) => {
    const timeoutId = setTimeout(callback, delay);
    timeoutsRef.current.push(timeoutId);
  };

  const setMenuState = (state) => {
    if (state === 'open') {
      document.body.setAttribute('data-menu-open', 'true');
      document.body.removeAttribute('data-menu-restoring');
      return;
    }

    if (state === 'restoring') {
      document.body.removeAttribute('data-menu-open');
      document.body.setAttribute('data-menu-restoring', 'true');
      queueTimeout(() => {
        document.body.removeAttribute('data-menu-restoring');
      }, 400);
      return;
    }

    document.body.removeAttribute('data-menu-open');
    document.body.removeAttribute('data-menu-restoring');
  };

  const closeMenu = (withRestore = true) => {
    if (!mobileOpen && !mobileClosing) {
      if (withRestore) setMenuState('restoring');
      return;
    }

    clearTimers();
    setMobileClosing(true);
    setMobileOpen(false);
    if (withRestore) {
      setMenuState('restoring');
    } else {
      setMenuState('closed');
    }
    queueTimeout(() => {
      setMobileClosing(false);
    }, 320);
  };

  const openMenu = () => {
    clearTimers();
    setMobileClosing(false);
    setMobileOpen(true);
    setMenuState('open');
  };

  const handleToggle = () => {
    if (mobileOpen) {
      closeMenu(true);
      return;
    }
    openMenu();
  };

  const animatePageOutIn = (key) => {
    const page = document.querySelector('.page-wrapper');
    if (page) {
      page.classList.remove('page-distort-in');
      void page.offsetWidth;
      page.classList.add('page-distort-out');
    }

    queueTimeout(() => {
      onNavigate(key);
    }, 350);

    queueTimeout(() => {
      const nextPage = document.querySelector('.page-wrapper');
      if (!nextPage) return;
      nextPage.classList.remove('page-distort-out');
      void nextPage.offsetWidth;
      nextPage.classList.add('page-distort-in');
      queueTimeout(() => {
        nextPage.classList.remove('page-distort-in');
      }, 420);
    }, 380);
  };

  const handleNavigate = (key) => {
    if (window.innerWidth <= 768) {
      closeMenu(false);
      queueTimeout(() => {
        animatePageOutIn(key);
      }, 150);
      return;
    }

    onNavigate(key);
  };

  useEffect(() => {
    return () => {
      clearTimers();
      setMenuState('closed');
    };
  }, []);

  return (
    <>
      <button
        type="button"
        className={`mobile-menu-toggle ${mobileOpen ? 'is-open' : ''}`}
        onClick={handleToggle}
        aria-label={mobileOpen ? 'Close navigation menu' : 'Open navigation menu'}
        aria-expanded={mobileOpen}
      >
        <span className="menu-line line-1" />
        <span className="menu-line line-2" />
        <span className="menu-line line-3" />
      </button>

      <div
        className={`mobile-nav-backdrop ${mobileOpen ? 'is-open' : ''}`}
        onClick={() => closeMenu(true)}
        aria-hidden="true"
      />

      <aside className="sidebar">
        <div className="sidebar-inner">
          <LogoMark />

          <nav className="sidebar-nav">
            {NAV_ITEMS.map((item) => (
              <button
                key={item.key}
                type="button"
                className={`nav-item ${activePage === item.key ? 'active' : ''}`}
                onClick={() => handleNavigate(item.key)}
              >
                <span className="active-bar" />
                <span className="icon">{item.icon}</span>
                <span className="label">{item.label}</span>
              </button>
            ))}
          </nav>

          <div className="availability">
            <span className="avail-dot" />
            <span>Available for work</span>
          </div>
        </div>
      </aside>

      <aside
        className={`mobile-sidebar ${mobileOpen ? 'is-open' : ''} ${mobileClosing ? 'is-closing' : ''}`}
      >
        <div className="sidebar-inner mobile-sidebar-inner">
          <LogoMark />

          <nav className={`sidebar-nav mobile-sidebar-nav ${mobileOpen ? 'drawer-open' : ''}`}>
            {NAV_ITEMS.map((item, index) => (
              <button
                key={item.key}
                type="button"
                className={`nav-item ${activePage === item.key ? 'active' : ''}`}
                onClick={() => handleNavigate(item.key)}
                style={{ animationDelay: `${index * 55}ms` }}
              >
                <span className="active-bar" />
                <span className="icon">{item.icon}</span>
                <span className="label">{item.label}</span>
              </button>
            ))}
          </nav>

          <div className="availability">
            <span className="avail-dot" />
            <span>Available for work</span>
          </div>
        </div>
      </aside>
    </>
  );
}
